#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <cuda_runtime.h>
#include <device_launch_parameters.h>

// Helper macros and functions to replace OpenCL utilities
#define cuda_errChk(status, msg, exitOnErr) \
    do { \
        if (status != cudaSuccess) { \
            fprintf(stderr, "CUDA Error: %s %s\n", cudaGetErrorString(status), msg); \
            if (exitOnErr) exit(-1); \
        } \
    } while (0)

void* alloc(size_t size) {
    void* ptr = malloc(size);
    if (ptr == NULL) {
        perror("malloc");
        exit(-1);
    }
    return ptr;
}

// Global timing variables
#ifdef TIMING
#include <sys/time.h>
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *r) {
    r->tv_sec = t1->tv_sec - t2->tv_sec;
    r->tv_usec = t1->tv_usec - t2->tv_usec;
    if (r->tv_usec < 0) {
        r->tv_sec--;
        r->tv_usec += 1000000;
    }
}
#else
// Define kernel_time even if TIMING is not set to avoid compilation errors in ForwardSub
float kernel_time = 0;
#endif

// CUDA Kernel for Fan1
__global__ void Fan1(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalId = threadIdx.x + blockIdx.x * blockDim.x;

    if (globalId < size - 1 - t) {
        m_dev[size * (globalId + t + 1) + t] = a_dev[size * (globalId + t + 1) + t] / a_dev[size * t + t];
    }
}

// CUDA Kernel for Fan2
__global__ void Fan2(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalIdx = threadIdx.x + blockIdx.x * blockDim.x;
    int globalIdy = threadIdx.y + blockIdx.y * blockDim.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        a_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] -= m_dev[size * (globalIdx + 1 + t) + t] * a_dev[size * t + (globalIdy + t)];

        if (globalIdy == 0) {
            b_dev[globalIdx + 1 + t] -= m_dev[size * (globalIdx + 1 + t) + t] * b_dev[t];
        }
    }
}

void InitMat(FILE *fp, int size, float *ary, int nrow, int ncol) {
    int i, j;
    for (i = 0; i < nrow; i++) {
        for (j = 0; j < ncol; j++) {
            fscanf(fp, "%f", ary + size * i + j);
        }
    }
}

void InitAry(FILE *fp, float *ary, int ary_size) {
    int i;
    for (i = 0; i < ary_size; i++) {
        fscanf(fp, "%f", &ary[i]);
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    int i, j;
    for (i = 0; i < nrow; i++) {
        for (j = 0; j < ncol; j++) {
            printf("%8.2e ", *(ary + size * i + j));
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    int i;
    for (i = 0; i < ary_size; i++) {
        printf("%.2e ", ary[i]);
    }
    printf("\n\n");
}

void InitPerRun(int size, float *m) {
    int i;
    for (i = 0; i < size * size; i++) {
        *(m + i) = 0.0;
    }
}

void BackSub(float *a, float *b, float *finalVec, int size) {
    int i, j;
    for (i = 0; i < size; i++) {
        finalVec[size - i - 1] = b[size - i - 1];
        for (j = 0; j < i; j++) {
            finalVec[size - i - 1] -= *(a + size * (size - i - 1) + (size - j - 1)) * finalVec[size - j - 1];
        }
        finalVec[size - i - 1] = finalVec[size - i - 1] / *(a + size * (size - i - 1) + (size - i - 1));
    }
}

void create_matrix(float *m, int size) {
    int i, j;
    float lamda = -0.01;
    float *coe = (float *)malloc((2 * size - 1) * sizeof(float));
    float coe_i = 0.0;

    for (i = 0; i < size; i++) {
        coe_i = 10 * exp(lamda * i);
        j = size - 1 + i;
        coe[j] = coe_i;
        j = size - 1 - i;
        coe[j] = coe_i;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            m[i * size + j] = coe[size - 1 - i + j];
        }
    }
    free(coe);
}

int parseCommandline(int argc, char *argv[], char* filename,
                     int *q, int *v, int *t, int *p, int *d, int *size) {
    int i;
    if (argc < 2) return 1;
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
            case 's':
                i++;
                *size = atoi(argv[i]);
                printf("Create matrix internally in parse, size = %d \n", *size);
                break;
            case 'f':
                i++;
                strncpy(filename, argv[i], 100);
                printf("Read file from %s \n", filename);
                break;
            case 'h':
                return 1;
                break;
            case 'q':
                *q = 1;
                break;
            case 'v':
                *v = 1;
                break;
            case 't':
                *t = 1;
                break;
            case 'p':
                i++;
                *p = atoi(argv[i]);
                break;
            case 'd':
                i++;
                *d = atoi(argv[i]);
                break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage() {
    printf("Gaussian Elimination Usage\n");
    printf("\n");
    printf("gaussianElimination [filename] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./gaussianElimination matrix4.txt\n");
    printf("\n");
    printf("filename     the filename that holds the matrix data\n");
    printf("\n");
    printf("-h           Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}

// Block size definitions
#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE_0 RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE_0 RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE_0 RD_WG_SIZE
#else
#define BLOCK_SIZE_0 256
#endif

#ifdef RD_WG_SIZE_1_0
#define BLOCK_SIZE_1_X RD_WG_SIZE_1_0
#elif defined(RD_WG_SIZE_1)
#define BLOCK_SIZE_1_X RD_WG_SIZE_1
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE_1_X RD_WG_SIZE
#else
#define BLOCK_SIZE_1_X 16
#endif

#ifdef RD_WG_SIZE_1_1
#define BLOCK_SIZE_1_Y RD_WG_SIZE_1_1
#elif defined(RD_WG_SIZE_1)
#define BLOCK_SIZE_1_Y RD_WG_SIZE_1
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE_1_Y RD_WG_SIZE
#else
#define BLOCK_SIZE_1_Y 16
#endif

void ForwardSub(float *a, float *b, float *m, int size, int timing) {
    float *a_dev, *b_dev, *m_dev;
    cudaEvent_t startEvent, stopEvent;
    float elapsed = 0.0f;

    // Allocate device memory
    cuda_errChk(cudaMalloc(&a_dev, sizeof(float) * size * size), "Allocating a_dev", true);
    cuda_errChk(cudaMalloc(&b_dev, sizeof(float) * size), "Allocating b_dev", true);
    cuda_errChk(cudaMalloc(&m_dev, sizeof(float) * size * size), "Allocating m_dev", true);

    // Create events
    cudaEventCreate(&startEvent);
    cudaEventCreate(&stopEvent);

    // Copy input data to device
    cuda_errChk(cudaMemcpy(a_dev, a, sizeof(float) * size * size, cudaMemcpyHostToDevice), "Copying a to device", true);
    cuda_errChk(cudaMemcpy(b_dev, b, sizeof(float) * size, cudaMemcpyHostToDevice), "Copying b to device", true);
    cuda_errChk(cudaMemcpy(m_dev, m, sizeof(float) * size * size, cudaMemcpyHostToDevice), "Copying m to device", true);

    // Define block and grid sizes
    dim3 block1(BLOCK_SIZE_0, 1, 1);
    dim3 block2(BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y, 1);

    int t;
    for (t = 0; t < (size - 1); t++) {
        // Fan1
        int gridSize1 = (size - 1 - t + block1.x - 1) / block1.x;
        if (gridSize1 == 0) gridSize1 = 1;

        cudaEventRecord(startEvent);
        Fan1<<<gridSize1, block1>>>(m_dev, a_dev, b_dev, size, t);
        cudaEventRecord(stopEvent);
        cudaEventSynchronize(stopEvent);
        cudaEventElapsedTime(&elapsed, startEvent, stopEvent);
        if (timing) kernel_time += elapsed / 1000.0f;

        // Fan2
        int gridX = (size - 1 - t + block2.x - 1) / block2.x;
        int gridY = (size - t + block2.y - 1) / block2.y;
        if (gridX == 0) gridX = 1;
        if (gridY == 0) gridY = 1;

        cudaEventRecord(startEvent);
        Fan2<<<dim3(gridX, gridY, 1), block2>>>(m_dev, a_dev, b_dev, size, t);
        cudaEventRecord(stopEvent);
        cudaEventSynchronize(stopEvent);
        cudaEventElapsedTime(&elapsed, startEvent, stopEvent);
        if (timing) kernel_time += elapsed / 1000.0f;
    }

    // Copy results back to host
    cuda_errChk(cudaMemcpy(a, a_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost), "Copying a to host", true);
    cuda_errChk(cudaMemcpy(b, b_dev, sizeof(float) * size, cudaMemcpyDeviceToHost), "Copying b to host", true);
    cuda_errChk(cudaMemcpy(m, m_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost), "Copying m to host", true);

    // Cleanup
    cudaFree(a_dev);
    cudaFree(b_dev);
    cudaFree(m_dev);
    cudaEventDestroy(startEvent);
    cudaEventDestroy(stopEvent);
}

int main(int argc, char *argv[]) {
    printf("WG size of kernel 1 = %d, WG size of kernel 2= %d X %d\n", BLOCK_SIZE_0, BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y);
    float *a = NULL, *b = NULL, *finalVec = NULL;
    float *m = NULL;
    int size = -1;

    FILE *fp;
    char filename[200];
    int show_data = 0, quiet = 0, timing = 0, platform = 0, device = 0;

    if (parseCommandline(argc, argv, filename,
                         &quiet, &show_data, &timing, &platform, &device, &size)) {
        printUsage();
        return 0;
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    if (size < 1) {
        fp = fopen(filename, "r");
        if (!fp) {
            printf("Error opening file: %s\n", filename);
            return -1;
        }
        fscanf(fp, "%d", &size);

        a = (float *)malloc(size * size * sizeof(float));
        InitMat(fp, size, a, size, size);

        b = (float *)malloc(size * sizeof(float));
        InitAry(fp, b, size);

        fclose(fp);
    } else {
        printf("create input internally before create, size = %d \n", size);

        a = (float *)malloc(size * size * sizeof(float));
        create_matrix(a, size);

        b = (float *)malloc(size * sizeof(float));
        for (int i = 0; i < size; i++)
            b[i] = 1.0;
    }

    if (!quiet && show_data) {
        printf("The input matrix a is:\n");
        PrintMat(a, size, size, size);

        printf("The input array b is:\n");
        PrintAry(b, size);
    }

    m = (float *)malloc(size * size * sizeof(float));
    finalVec = (float *)malloc(size * sizeof(float));

    InitPerRun(size, m);

    // Execute Forward Substitution (GPU)
    ForwardSub(a, b, m, size, timing);

    if (!quiet && show_data) {
        printf("The result of matrix m is: \n");
        PrintMat(m, size, size, size);
        printf("The result of matrix a is: \n");
        PrintMat(a, size, size, size);
        printf("The result of array b is: \n");
        PrintAry(b, size);

        BackSub(a, b, finalVec, size);
        printf("The final solution is: \n");
        PrintAry(finalVec, size);
    }

    free(m);
    free(a);
    free(b);
    free(finalVec);

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    cudaDeviceReset();

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return 0;
}
